h = int(input("Высота: "))
L = int(input("Длина: "))
pos = mc.player.getTilePos()
for i in range(L):
    for j in range(h):
        if i == L // 2 and j < 2:
            mc.setBlock(pos.x + i, pos.y + j, pos.z, block.AIR.id)
        else:
            mc.setBlock(pos.x + i, pos.y + j, pos.z, block.COBBLESTONE.id)
